// Build Gemini YouTube Request
const input = $('Execute Workflow Trigger').first().json;
const url = input.url || input.query || '';

// Extract video ID from various YouTube URL formats
let videoId = '';
const patterns = [
  /[?&]v=([a-zA-Z0-9_-]{11})/,
  /youtu\.be\/([a-zA-Z0-9_-]{11})/,
  /embed\/([a-zA-Z0-9_-]{11})/,
  /shorts\/([a-zA-Z0-9_-]{11})/
];
for (const p of patterns) {
  const m = url.match(p);
  if (m) { videoId = m[1]; break; }
}

if (!videoId) {
  return [{json: {
    result: "I couldn't extract a valid YouTube video ID from that URL. Please share a standard youtube.com or youtu.be link.",
    media_type: 'youtube'
  }}];
}

const videoUrl = 'https://www.youtube.com/watch?v=' + videoId;

const body = JSON.stringify({
  contents: [{
    parts: [
      {text: "Summarize this YouTube video. Be natural and conversational, highlighting the key points, main ideas, and any important details. Give a thorough but readable summary."},
      {file_data: {file_uri: videoUrl}}
    ]
  }],
  generationConfig: {
    maxOutputTokens: 8192
  }
});

return [{json: {
  requestBody: body,
  videoId: videoId,
  url: videoUrl
}}];

// Format YouTube Result
const response = $json;
const req = $('Build Gemini Request').first().json;

let result;
if (response.candidates && response.candidates[0]?.content?.parts?.[0]?.text) {
  result = response.candidates[0].content.parts[0].text;
} else if (response.error) {
  result = `I wasn't able to pull up that video — ${response.error.message || 'something went wrong on my end'}.`;
} else {
  result = "I wasn't able to process that video — it might be private, age-restricted, or not yet indexed.";
}

return [{json: {
  result,
  media_type: 'youtube',
  filename: 'youtube_video'
}}];
